import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.DrTRbHdy.js";const u=JSON.parse('{"title":"地图控件开发规范","description":"","frontmatter":{},"headers":[],"relativePath":"CONTROLS.md","filePath":"CONTROLS.md"}'),d={name:"CONTROLS.md"};function l(i,e,s,n,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="地图控件开发规范" tabindex="-1">地图控件开发规范 <a class="header-anchor" href="#地图控件开发规范" aria-label="Permalink to &quot;地图控件开发规范&quot;">​</a></h1><h2 id="_1-布局约定" tabindex="-1">1. 布局约定 <a class="header-anchor" href="#_1-布局约定" aria-label="Permalink to &quot;1. 布局约定&quot;">​</a></h2><ul><li><strong>右侧</strong>：所有<strong>控制类插件</strong>（底图切换、主题/样式控制、图例、图层列表等）统一在右侧自上而下排列，与主操作区分离。</li><li><strong>左下角</strong>：<strong>状态/信息类</strong>内容（层级、鼠标实时经纬度、比例尺等）放置在软件左下角，使用主题变量以适配亮/暗色。</li></ul><h2 id="_2-控件分类" tabindex="-1">2. 控件分类 <a class="header-anchor" href="#_2-控件分类" aria-label="Permalink to &quot;2. 控件分类&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>位置</th><th>说明</th></tr></thead><tbody><tr><td>控制类</td><td>右侧</td><td>底图切换、主题切换、图例、图层控制等，可点击、可展开。</td></tr><tr><td>状态类</td><td>左下角</td><td>仅展示信息：缩放层级、鼠标经纬度、比例尺等，随主题样式。</td></tr></tbody></table><h2 id="_3-样式与主题" tabindex="-1">3. 样式与主题 <a class="header-anchor" href="#_3-样式与主题" aria-label="Permalink to &quot;3. 样式与主题&quot;">​</a></h2><ul><li>控件样式统一使用 <strong>主题样式表</strong>（<code>theme.css</code>）中的 CSS 变量，便于亮/暗色切换与整体一致。</li><li>新增控件时使用变量：<code>--CelestiaWeather-bg</code>、<code>--CelestiaWeather-color</code>、<code>--CelestiaWeather-border</code>、<code>--CelestiaWeather-shadow</code> 等，避免硬编码色值。</li></ul><h2 id="_4-交互与穿透" tabindex="-1">4. 交互与穿透 <a class="header-anchor" href="#_4-交互与穿透" aria-label="Permalink to &quot;4. 交互与穿透&quot;">​</a></h2><ul><li>UI 层容器保持 <strong>点击穿透</strong>（<code>pointer-events: none</code>），不阻挡地图操作。</li><li>每个控件的<strong>根节点</strong>单独设置 <code>pointer-events: auto</code>，保证本控件可点击，其余区域事件落到地图。</li></ul><h2 id="_5-新增控件步骤" tabindex="-1">5. 新增控件步骤 <a class="header-anchor" href="#_5-新增控件步骤" aria-label="Permalink to &quot;5. 新增控件步骤&quot;">​</a></h2><ol><li>在 <code>src/vue/components/</code> 下新增组件，控制类放在右侧容器内，状态类放在左下角容器内。</li><li>在 <code>App.vue</code> 中按类型放入对应区域（右侧列 / 左下角）。</li><li>在 <code>MapClass</code> 的 options 中增加对应开关（如 <code>showXxx</code>），并传入 Vue。</li><li>样式引用主题变量，见 <code>src/styles/theme.css</code>。</li></ol>',11)])])}const b=t(d,[["render",l]]);export{u as __pageData,b as default};
